import { exec, execSync } from "node:child_process";
import http from "node:http";
import os from "node:os";
import readline from "node:readline";
import { getConfig, saveCredentials } from "../config.js";
const LOGIN_TIMEOUT_MS = 10 * 60 * 1000;
const AGENT_TIMEOUT_MS = 90 * 1000;
const AGENT_HINT_DELAY_MS = 30 * 1000;
const PASTE_HINT_DELAY_MS = 8 * 1000;
function openBrowser(url) {
    const platform = os.platform();
    const cmd = platform === "darwin" ? "open" : platform === "win32" ? "start" : "xdg-open";
    exec(`${cmd} "${url}"`);
}
export function findOpenPort() {
    return new Promise((resolve, reject) => {
        const server = http.createServer();
        server.listen(0, () => {
            const addr = server.address();
            if (addr && typeof addr === "object") {
                const port = addr.port;
                server.close(() => resolve(port));
            }
            else {
                reject(new Error("Could not find open port"));
            }
        });
    });
}
export function getFrontmostApp() {
    if (os.platform() !== "darwin") {
        return null;
    }
    try {
        return execSync(`osascript -e 'tell application "System Events" to get name of first process whose frontmost is true'`, { stdio: "pipe", encoding: "utf-8" }).trim();
    }
    catch {
        return null;
    }
}
export function focusApp(appName) {
    if (!appName || os.platform() !== "darwin") {
        return;
    }
    exec(`osascript -e 'tell application "${appName}" to activate'`);
}
const CALLBACK_HTML = `<html>
<body style="margin:0;background:#f8fafc;color:#0f172a;font-family:system-ui,-apple-system,sans-serif;display:flex;align-items:center;justify-content:center;height:100vh;overflow:hidden">
  <div style="text-align:center;max-width:400px">
    <h1 style="font-size:24px;font-weight:600;margin:0 0 16px 0">Bitfab</h1>
    <p style="margin:0;color:#059669">Authenticated! You can close this window.</p>
    <button onclick="window.close()" style="margin-top:16px;padding:8px 16px;background:#0f172a;color:white;border:none;border-radius:8px;font-size:14px;font-weight:500;cursor:pointer">Close Window</button>
  </div>
</body>
<script>window.close()</script>
</html>`;
async function verifyToken(serviceUrl, token) {
    try {
        const res = await fetch(`${serviceUrl}/api/plugin/whoami`, {
            headers: { Authorization: `Bearer ${token}` },
        });
        if (!res.ok) {
            return null;
        }
        return (await res.json());
    }
    catch {
        return null;
    }
}
/**
 * Race a loopback HTTP callback against a stdin-paste fallback to obtain an
 * API key from the browser. Whichever path delivers a valid token first wins;
 * the other is torn down.
 *
 * Known gap: this flow does not yet use PKCE, so a malicious process on the
 * same machine that binds the loopback port before us could intercept the
 * token. The same gap exists in the previous version of this command. Adding
 * PKCE requires server-side state (an auth_codes table) and is tracked as a
 * follow-up.
 */
export async function runLogin(platform) {
    const config = getConfig();
    const previousApp = getFrontmostApp();
    const port = await findOpenPort();
    const isRemoteSSH = Boolean(process.env.SSH_CLIENT || process.env.SSH_TTY);
    const authUrl = `${config.serviceUrl}/plugin/auth/${platform.authPath}?port=${port}`;
    console.log("\nOpening your browser to sign in...");
    console.log(`  ${authUrl}`);
    console.log("");
    if (isRemoteSSH) {
        console.log("SSH session detected — the browser callback probably can't reach this machine.");
        console.log("Visit the URL above, then copy the token shown on the page and paste it here.");
    }
    else {
        console.log("(If the browser didn't open, visit the URL above manually.)");
    }
    openBrowser(authUrl);
    let resolved = false;
    let resolveToken = () => { };
    let rejectToken = () => { };
    const tokenPromise = new Promise((resolve, reject) => {
        resolveToken = (token) => {
            if (resolved) {
                return;
            }
            resolved = true;
            resolve(token);
        };
        rejectToken = (err) => {
            if (resolved) {
                return;
            }
            resolved = true;
            reject(err);
        };
    });
    const server = http.createServer((req, res) => {
        res.setHeader("Access-Control-Allow-Origin", "*");
        res.setHeader("Access-Control-Allow-Methods", "GET, OPTIONS");
        if (req.method === "OPTIONS") {
            res.writeHead(204);
            res.end();
            return;
        }
        const url = new URL(req.url ?? "/", `http://localhost:${port}`);
        if (url.pathname === "/health") {
            res.writeHead(200, { "Content-Type": "application/json" });
            res.end(JSON.stringify({ ok: true }));
        }
        else if (url.pathname === "/callback") {
            const token = url.searchParams.get("token");
            if (token) {
                res.writeHead(200, { "Content-Type": "text/html" });
                res.end(CALLBACK_HTML);
                resolveToken(token);
            }
            else {
                res.writeHead(400, { "Content-Type": "application/json" });
                res.end(JSON.stringify({ ok: false, error: "No token received" }));
            }
        }
        else {
            res.writeHead(404);
            res.end();
        }
    });
    server.on("error", (err) => {
        rejectToken(new Error(`Loopback server error: ${err.message}`));
    });
    server.listen(port);
    // The readline paste fallback only makes sense when stdin is an interactive
    // TTY. Under Claude Code / Cursor the plugin runs via the agent's Bash tool,
    // which pipes stdin and has no human typing — in that case we skip the
    // readline setup entirely so we don't print a useless paste hint into the
    // subprocess output. For agent-driven environments the `login headless`
    // flow in setup.md is used instead.
    const interactive = process.stdin.isTTY === true;
    const rl = interactive
        ? readline.createInterface({
            input: process.stdin,
            output: process.stdout,
        })
        : null;
    const hintTimer = interactive && !isRemoteSSH
        ? setTimeout(() => {
            if (resolved) {
                return;
            }
            console.log("");
            console.log("Having trouble? If your browser shows a token, paste it here and press Enter:");
        }, PASTE_HINT_DELAY_MS)
        : null;
    rl?.on("line", async (line) => {
        if (resolved) {
            return;
        }
        const trimmed = line.trim();
        if (!trimmed) {
            return;
        }
        process.stdout.write("Verifying token... ");
        const who = await verifyToken(config.serviceUrl, trimmed);
        if (who) {
            console.log("ok.");
            resolveToken(trimmed);
        }
        else {
            console.log("invalid token. Try again or complete the browser flow.");
        }
    });
    // In agent mode (non-TTY) the only thing that can arrive is the loopback
    // callback. If it hasn't landed in ~90s, something is structurally wrong
    // (SSH, sandbox, firewall) and the agent should take over with the headless
    // flow immediately — no point waiting 10 minutes. We print progress
    // messages so the agent (reading stdout after exit) has clear context.
    const timeoutMs = interactive ? LOGIN_TIMEOUT_MS : AGENT_TIMEOUT_MS;
    const agentHintTimer = !interactive
        ? setTimeout(() => {
            if (resolved) {
                return;
            }
            console.log("Still waiting for the browser callback... If you're on a remote machine (SSH, Codespaces, cloud IDE), the callback may not be able to reach this terminal.");
        }, AGENT_HINT_DELAY_MS)
        : null;
    const timeoutTimer = setTimeout(() => {
        const headlessUrl = `${config.serviceUrl}/plugin/auth/${platform.authPath}`;
        if (interactive) {
            rejectToken(new Error("Authentication timed out after 10 minutes. Run login again."));
        }
        else {
            rejectToken(new Error(`Authentication callback not received. The browser at ${headlessUrl} should show your token — copy it and paste it into the chat to complete login.`));
        }
    }, timeoutMs);
    function cleanup() {
        if (hintTimer) {
            clearTimeout(hintTimer);
        }
        if (agentHintTimer) {
            clearTimeout(agentHintTimer);
        }
        clearTimeout(timeoutTimer);
        server.close();
        rl?.close();
    }
    try {
        const token = await tokenPromise;
        cleanup();
        saveCredentials(token);
        const who = await verifyToken(config.serviceUrl, token);
        const greeting = who?.user.email
            ? `Logged in as ${who.user.email}.`
            : "Authentication successful.";
        console.log(`\n${greeting}`);
        console.log("Bitfab MCP tools are now active.");
        focusApp(previousApp);
        process.exit(0);
    }
    catch (err) {
        cleanup();
        console.error(`\n${err.message}`);
        process.exit(1);
    }
}
